INSERT INTO `sys_config` VALUES (101,1,1,'网站域名','websiteDomain','http://localhost/',_binary '','网站主域名，注意以斜杠结尾',1,'2021-12-10 14:28:29','2024-06-04 11:10:16'),(102,1,1,'网站名称','websiteName','在线防灾教育系统',_binary '','网站名称',2,'2022-06-18 17:29:48','2025-03-14 16:03:05'),(103,1,3,'网站LOGO','websiteLogo','http://127.0.0.1:9000/education/public/226a73f2065c4908823388f45c175860.png',_binary '','网站LOGO带文字和图标，建议尺寸 510×108px',10,'2022-02-18 14:57:23','2025-03-14 16:04:37'),(104,1,3,'网站ICON','websiteIcon','http://127.0.0.1:9000/education/public/226a73f2065c4908823388f45c175860.png',_binary '','网站ICON，建议尺寸 64×64px',30,'2022-02-18 14:55:47','2025-03-14 16:04:42'),(105,1,1,'网站描述','websiteDesc','在线防灾教育系统是依托数字技术打造的综合性安全教育平台，旨在通过多媒体课程、虚拟演练和智能评估等方式，提升公众应对自然灾害及突发事件的应急能力。系统涵盖地震、火灾、洪水等灾害知识库，结合 3D 场景模拟逃生路径选择、急救操作等实战训练，支持 PC 端与移动端多设备访问。平台采用 AI 算法分析用户学习行为，提供个性化风险预警与防灾建议，并整合政府应急部门数据，实时更新灾害预警信息。其核心优势在于打破传统教育的时空限制，通过互动化、游戏化的学习模式增强公众防灾意识，助力社区、学校及企事业单位构建科学防灾体系。',_binary '','用于在店铺登录页面底部展示，例如：“**科技·知识产品与用户服务的数字化工具”',40,'2022-02-18 16:40:27','2025-03-14 16:05:50'),(106,1,1,'网站版权','websiteCopyright','© 2025-牛逼技术有限公司',_binary '','例如：“Copyright © 2015-现在 ******网络技术有限公司 All Rights Reserved”',50,'2022-02-18 16:32:40','2025-03-14 16:06:21'),(107,1,1,'网站ICP','websiteIcp','粤ICP备99999999号 -1',_binary '','例如：“粤ICP备********号-1”',60,'2022-02-18 16:34:32','2025-03-14 16:06:30'),(108,1,1,'公安部备案号','websitePrn','粤公网安备9999999号',_binary '','公安部备案号',70,'2022-03-22 11:47:44','2025-03-14 16:06:36'),(110,1,2,'网站用户协议','websiteUserAgreement','<p style=\"text-align: left;\"><span style=\"color: rgba(0, 0, 0, 0.85); background-color: rgb(255, 255, 255); font-size: 16px;\">在线防灾教育系统是依托数字技术打造的综合性安全教育平台，旨在通过多媒体课程、虚拟演练和智能评估等方式，提升公众应对自然灾害及突发事件的应急能力。系统涵盖地震、火灾、洪水等灾害知识库，结合 3D 场景模拟逃生路径选择、急救操作等实战训练，支持 PC 端与移动端多设备访问。平台采用 AI 算法分析用户学习行为，提供个性化风险预警与防灾建议，并整合政府应急部门数据，实时更新灾害预警信息。其核心优势在于打破传统教育的时空限制，通过互动化、游戏化的学习模式增强公众防灾意识，助力社区、学校及企事业单位构建科学防灾体系。</span></p>',_binary '\0','网站用户协议',100,'2022-09-24 14:47:36','2025-03-14 16:06:46'),(210,2,1,'RSA公